static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
  assert(Cases.size() >= 1);

  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
  for (size_t I = 1, E = Cases.size(); I != E; ++I) {
    if (Cases[I]->getValue() != Cases[I - 1]->getValue() + 1)
      return false;
  }
  return true;
}

/// Check if adding a constant offset to each case value would make them
/// form a contiguous range (with unsigned wrap-around).
/// If so, store the offset needed (which is the negation of the minimum value
/// in the wrapping interpretation) in OptimalOffset.
static bool
getWrappingRangeOffset(SmallVectorImpl<ConstantInt *> &Cases,
                       ConstantInt *&OptimalOffset) {
  assert(Cases.size() >= 1);

  // Sort the case values
  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);

  unsigned BitWidth = Cases[0]->getType()->getBitWidth();
  APInt MaxGap = APInt::getMaxValue(BitWidth);
  APInt TotalGap = APInt::getZero(BitWidth);

  // Compute the size of gaps between consecutive values
  // We want to find the location where wrapping would give us the smallest
  // contiguous range
  unsigned NumGaps = Cases.size();
  APInt MinValue = Cases[0]->getValue();
  APInt MaxValue = Cases[Cases.size() - 1]->getValue();

  for (size_t I = 1, E = Cases.size(); I != E; ++I) {
    APInt Gap = Cases[I]->getValue() - Cases[I - 1]->getValue();
    // We're looking for the largest gap - if we wrap across that gap,
    // the values become contiguous
    if (Gap.ugt(MaxGap))
      MaxGap = Gap;
    TotalGap += Gap;
  }

  // Compute the wrap-around gap
  APInt WrapGap;
  if (Cases.size() >= 1) {
    APInt Zero = APInt::getZero(BitWidth);
    WrapGap = (APInt::getMaxValue(BitWidth) - MaxValue) + MinValue + 1;
  } else {
    WrapGap = APInt::getZero(BitWidth);
  }

  // Check if wrapping across the largest gap makes them contiguous.
  // The non-wrapped gap should be larger than all the internal gaps combined.
  // Actually, we need: MaxGap - 1 == (MaxValue - MinValue) - (Cases.size() - 1)
  // Which means: TotalGap + WrapGap - MaxGap == Cases.size() - 1
  APInt TotalRange = TotalGap + WrapGap;
  if (TotalRange.ult(Cases.size()))
    return false;

  APInt InternalRange = TotalRange - MaxGap;
  // Internal range should be Cases.size() - 1 for a contiguous wrapped range
  if (InternalRange != APInt(BitWidth, Cases.size() - 1))
    return false;

  // The optimal offset is the negation of the maximum value so that
  // the wrapped range starts at 0
  // We want: (MaxValue + Offset) to be Cases.size() - 1
  // So: Offset = Cases.size() - 1 - MaxValue
  OptimalOffset = ConstantInt::get(Cases[0]->getType(),
                                   Cases.size() - 1);
  OptimalOffset = ConstantExpr::getSub(OptimalOffset,
                                       cast<ConstantInt>(ConstantInt::get(
                                           Cases[0]->getType(), MaxValue)));
  return true;
}
